import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"JO",currency:"JOD",flag:"🇯🇴",nameEn:"Jordan",nameAr:"الأردن",fixedPeg:!1,decimals:3,timezone:"Asia/Amman",relatedCountries:[{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"morocco.html",nameEn:"Morocco",nameAr:"المغرب",flag:"🇲🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"india.html",nameEn:"India",nameAr:"الهند",flag:"🇮🇳"}],faqEn:[{q:"What is today's gold price in Jordan?",a:"The Jordanian Dinar (JOD) is pegged to the US Dollar at a fixed rate of 0.709 JOD per USD, making it one of the most stable currencies in the Arab world. Gold prices in Jordan follow global XAU/USD movements directly. Prices on this page are updated every 90 seconds."},{q:"What karats are popular in Jordan?",a:"21K is the dominant karat for traditional Jordanian jewellery and remains the standard in the local gold market. 18K has grown in popularity for modern and Italian-influenced designs. 24K gold bars and coins are available for investors."},{q:"Where can I buy gold in Jordan?",a:"Amman's downtown Gold Market near the Husseini Mosque is the traditional centre for gold trading in Jordan, with hundreds of jewellers in a concentrated area. The Sweifieh neighbourhood in west Amman also has a large concentration of upmarket gold and jewellery shops."},{q:"Is gold a good investment in Jordan?",a:"Gold is a widely popular store of value in Jordan given the stable JOD peg and regional economic uncertainty. Certified investment gold bars issued through the Central Bank of Jordan are a trusted option for Jordanian investors looking to hold physical gold."}],faqAr:[{q:"ما هو سعر الذهب اليوم في الأردن؟",a:"يرتبط الدينار الأردني (JOD) بالدولار الأمريكي بسعر صرف ثابت قدره 0.709 دينار لكل دولار، مما يجعله من أكثر العملات استقراراً في العالم العربي. تتبع أسعار الذهب في الأردن مباشرةً تحركات XAU/USD العالمية. يتم تحديث الأسعار في هذه الصفحة كل 90 ثانية."},{q:"ما هي العيارات الأكثر شيوعاً في الأردن؟",a:"يُعدّ عيار 21 العيار السائد للمجوهرات الأردنية التقليدية ويبقى المعيار الرئيسي في السوق المحلية. اكتسب عيار 18 شعبيةً متزايدة للتصاميم الحديثة والمستوحاة من الطراز الإيطالي. وتتوفر سبائك وعملات عيار 24 للمستثمرين."},{q:"أين يمكنني شراء الذهب في الأردن؟",a:"يُعدّ سوق الذهب في وسط عمان بالقرب من الجامع الحسيني المركز التقليدي لتجارة الذهب في الأردن، إذ يضم مئات الصاغة في منطقة متقاربة. كما يشتهر حي الصويفية في غرب عمان بتركّز كبير من محلات الذهب والمجوهرات الراقية."},{q:"هل يُعدّ الذهب استثماراً جيداً في الأردن؟",a:"يُعدّ الذهب وسيلةً شائعةً لحفظ القيمة في الأردن في ظل استقرار ربط الدينار وحالة عدم اليقين الاقتصادي الإقليمي. وتُعدّ السبائك الذهبية الاستثمارية المعتمدة الصادرة عن البنك المركزي الأردني خياراً موثوقاً للمستثمرين الأردنيين الراغبين في الاحتفاظ بالذهب الفيزيائي."}]});
